// /frontend/src/components/Radar.jsx
import React, { useEffect, useRef, useState } from "react";
import L from "leaflet";
import "leaflet/dist/leaflet.css";

/**
 * Uses OpenWeather tile layers:
 *  - precipitation_new: rain intensity
 *  - snow_new: snow intensity
 * You can toggle the snow overlay. Heavy precip trends toward red on OW tiles.
 */

const DEFAULT_CENTER = [33.749, -84.388]; // ATL; adjust if you want
const DEFAULT_ZOOM = 6;

export default function Radar() {
  const mapRef = useRef(null);
  const precipRef = useRef(null);
  const snowRef = useRef(null);
  const [loading, setLoading] = useState(true);
  const [showSnow, setShowSnow] = useState(true);
  const [errorText, setErrorText] = useState("");

  const appid = process.env.REACT_APP_OWM_KEY || import.meta?.env?.VITE_OWM_KEY;

  useEffect(() => {
    if (mapRef.current) return;

    // Guard: without an API key, tiles won't render
    if (!appid) {
      setErrorText("Missing OpenWeather API key (REACT_APP_OWM_KEY).");
      setLoading(false);
      return;
    }

    const map = L.map("radar-map", {
      zoomControl: false,
      attributionControl: false,
      preferCanvas: true,
    }).setView(DEFAULT_CENTER, DEFAULT_ZOOM);

    // Base map (dark)
    L.tileLayer(
      "https://{s}.tile.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png",
      { subdomains: "abcd", maxZoom: 18, opacity: 0.95 }
    ).addTo(map);

    // Precipitation (shows quickly)
    const precip = L.tileLayer(
      `https://tile.openweathermap.org/map/precipitation_new/{z}/{x}/{y}.png?appid=${appid}`,
      { opacity: 0.85, zIndex: 500, crossOrigin: true }
    )
      .on("load", () => setLoading(false))
      .on("tileerror", () => setErrorText("Radar tiles failed to load."))
      .addTo(map);

    precipRef.current = precip;

    // Snow overlay (toggled)
    const snow = L.tileLayer(
      `https://tile.openweathermap.org/map/snow_new/{z}/{x}/{y}.png?appid=${appid}`,
      { opacity: 0.9, zIndex: 510, crossOrigin: true }
    );

    snowRef.current = snow;
    if (showSnow) snow.addTo(map);

    mapRef.current = map;

    // Ensure proper sizing if parent layout shifts
    setTimeout(() => map.invalidateSize(), 0);
  }, [appid]);

  // Toggle snow overlay
  useEffect(() => {
    const map = mapRef.current;
    const snow = snowRef.current;
    if (!map || !snow) return;

    if (showSnow) {
      if (!map.hasLayer(snow)) snow.addTo(map);
    } else {
      if (map.hasLayer(snow)) map.removeLayer(snow);
    }
  }, [showSnow]);

  return (
    <div className="relative rounded-2xl overflow-hidden backdrop-blur-xl bg-black/40 ring-1 ring-white/10">
      <div className="flex items-center justify-between px-3 py-2">
        <div className="text-sm opacity-80">Radar</div>
        <div className="flex items-center gap-2">
          <label className="text-xs flex items-center gap-1">
            <input
              type="checkbox"
              checked={showSnow}
              onChange={(e) => setShowSnow(e.target.checked)}
            />
            Snow overlay
          </label>
        </div>
      </div>

      <div id="radar-map" className="w-full" style={{ height: 320 }} />

      {loading && (
        <div className="absolute inset-0 grid place-items-center">
          <div className="animate-spin h-6 w-6 rounded-full border-2 border-white/30 border-top-white" />
        </div>
      )}

      {!!errorText && !loading && (
        <div className="absolute bottom-2 left-2 right-2 text-xs px-2 py-1 rounded bg-black/70 ring-1 ring-white/10">
          {errorText}
        </div>
      )}

      {/* Legend */}
      <div className="absolute bottom-3 left-3 text-[11px] rounded bg-black/60 px-2 py-1 ring-1 ring-white/10">
        <div className="font-medium mb-1">Precip Intensity</div>
        <div className="flex items-center gap-2">
          <span className="inline-block h-2 w-6 bg-yellow-400" /> Moderate
          <span className="inline-block h-2 w-6 bg-red-500" /> Heavy (red)
          <span className="inline-block h-2 w-6 bg-blue-400" /> Snow overlay
        </div>
      </div>
    </div>
  );
}
